local TD = TD.td1madao["ydj_dst_td1madao"] local MADAO = TD.CONST() local function runLifecycle(name)     local lifecycle = MADAO[name]     if string.td1madao_notEmpty(name) and TD.isTab(lifecycle) then         for k, obj in pairs(lifecycle) do             local fn = obj.fn             local n = obj.n             local v = obj.v             fn(unpack(v, 1, n))         end     end end if _G.ResumeRequestLoadComplete then     local old = _G.ResumeRequestLoadComplete     _G.ResumeRequestLoadComplete = function(...)         runLifecycle("LIFECYCLE")         old(...)     end end AddClassPostConstruct("widgets/controls", function()     runLifecycle("LIFECYCLE") end) local ModWranglerCycle = false local ModManager = _G.ModManager local oldfun = ModManager.RegisterPrefabs ModManager.RegisterPrefabs = function(...)     if not ModWranglerCycle then         ModWranglerCycle = true         runLifecycle("LIFECYCLE")         runLifecycle("BEFOREPREFAB")     end     oldfun(...) end 